" prompt += self._format_messages(messages) 3. Preservation Rules Engine Add a simple rules engine that processes provider directives before summary generation: # Example rules that providers can specify PRESERVATION_RULES = { "keep_last_file_path": lambda msgs: extract_last_pattern(msgs, r'(/[\w./-]+\.\w+)'), "keep_last_error": lambda msgs: extract_last_error_resolution(msgs), "keep_last_decision": lambda msgs: extract_last_decision(msgs), "keep_user_preferences": lambda msgs: extract_preferences(msgs), } Use Case: Muninn Memory Plugin The Muninn plugin extracts structured information from conversations — file paths, URLs, decisions, corrections. With the current str return, it can only append a digest. With CompressionContext , it can: class MuninnMemoryProvider(MemoryProvider): def on_pre_compress(self, messages) -> CompressionContext: # Extract and save memories externally (already works) self._extract_compression_memories(messages) # Build structured context for the compressor return CompressionContext( text=self._build_compression_digest(messages), key_facts=[ f"Active project: {self._detect_project(messages)}", f"Last file modified: {self._find_last_path(messages)}", ], preservation_rules=[ "keep_last_file_path", "keep_user_preferences", ], )
